interface CartItemProps {
  item: {
    id: string;
    name: string;
    price: number;
    quantity: number;
    image: string;
  };
  onUpdateQuantity: (id: string, quantity: number) => void;
  onRemove: (id: string) => void;
}

const CartItem = ({ item, onUpdateQuantity, onRemove }: CartItemProps) => (
  <div className="flex items-center gap-4 p-4 bg-gray-800 rounded-xl">
    <img src={item.image} alt={item.name} className="w-16 h-16 object-cover rounded-lg" />
    <div className="flex-1">
      <h4 className="text-white font-medium">{item.name}</h4>
      <p className="text-gray-400">${item.price.toFixed(2)}</p>
      <div className="flex items-center gap-2 mt-2">
        <button onClick={() => onUpdateQuantity(item.id, item.quantity - 1)} className="px-2 py-1 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition">
          -
        </button>
        <span className="text-white">{item.quantity}</span>
        <button onClick={() => onUpdateQuantity(item.id, item.quantity + 1)} className="px-2 py-1 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition">
          +
        </button>
      </div>
    </div>
    <button onClick={() => onRemove(item.id)} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-500 transition">
      Remove
    </button>
  </div>
);

export default CartItem;

